<template><div class="space-y-6"><div class="bg-white p-3 rounded-xl shadow-sm border border-gray-200"><div class="flex flex-wrap xl:flex-nowrap gap-2 items-center"><div class="relative flex-1 min-w-[200px]"><input type="text" v-model="searchQuery" placeholder="Cari kode atau cabang..." class="w-full pl-9 pr-3 py-2 text-sm border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"><i class="fa-solid fa-magnifying-glass absolute left-3 top-2.5 text-gray-400 text-xs"></i></div><select v-if="userData?.role === 'admin'" v-model="filterCabang" class="p-2 border border-gray-300 rounded-lg text-xs focus:ring-2 focus:ring-blue-500 outline-none bg-white font-medium cursor-pointer"><option value="">Semua Cabang</option><option v-for="c in storeList" :key="c" :value="c">{{ c }}</option></select><div class="flex items-center border border-gray-300 rounded-lg overflow-hidden bg-white"><input type="date" v-model="startDate" class="px-2 py-1.5 text-xs focus:outline-none cursor-pointer border-none"><span class="text-gray-400 text-xs px-0.5">-</span><input type="date" v-model="endDate" class="px-2 py-1.5 text-xs focus:outline-none cursor-pointer border-none"><button v-if="startDate || endDate" @click="resetDateFilter" class="px-2 bg-gray-50 hover:bg-red-50 text-gray-500 hover:text-red-600 transition text-xs"><i class="fa-solid fa-xmark"></i></button></div><div class="flex items-center gap-2 xl:ml-auto"><button @click="exportToExcel" class="flex items-center gap-1.5 px-3 py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg transition text-xs font-medium shadow-sm whitespace-nowrap"><i class="fa-solid fa-file-arrow-down"></i> Export</button><button @click="openModal" class="flex items-center gap-1.5 px-3 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition text-xs font-medium shadow-sm whitespace-nowrap"><i class="fa-solid fa-plus"></i> Tambah</button></div></div></div><div class="bg-white rounded-xl shadow-sm border border-gray-200 ove