rsor-pointer hover:bg-gray-100 select-none group relative"><div class="flex items-center justify-end gap-1">Pengeluaran <i v-if="sortKey === 'expense'" class="fa-solid text-blue-600" :class="sortAsc ? 'fa-sort-up' : 'fa-sort-down'"></i><i v-else class="fa-solid fa-sort text-gray-300 opacity-0 group-hover:opacity-100"></i></div><div class="absolute top-full right-0 mt-2 w-max bg-gray-900 text-white text-xs rounded py-1.5 px-3 opacity-0 group-hover:opacity-100 transition-opacity z-50 pointer-events-none shadow-lg">Total: <span class="font-bold text-red-300">{{ formatRupiah(grandTotals.expense) }}</span></div></th><th @click="sortBy('totalAll')" class="px-4 py-3 text-right cursor-pointer hover:bg-gray-100 select-none group relative"><div class="flex items-center justify-end gap-1">Total <i v-if="sortKey === 'totalAll'" class="fa-solid text-blue-600" :class="sortAsc ? 'fa-sort-up' : 'fa-sort-down'"></i><i v-else class="fa-solid fa-sort text-gray-300 opacity-0 group-hover:opacity-100"></i></div><div class="absolute top-full right-0 mt-2 w-max bg-gray-900 text-white text-xs rounded py-1.5 px-3 opacity-0 group-hover:opacity-100 transition-opacity z-50 pointer-events-none shadow-lg">Total: <span class="font-bold text-green-300">{{ formatRupiah(grandTotals.totalAll) }}</span></div></th><th @click="sortBy('serba35')" class="px-4 py-3 text-center cursor-pointer hover:bg-gray-100 select-none group relative"><div class="flex items-center justify-center gap-1">Serba 35 <i v-if="sortKey === 'serba35'" class="fa-solid text-blue-600" :class="sortAsc ? 'fa-sort-up' : 'fa-sort-down'"></i><i v-else class="fa-solid fa-sort text-gray-300 opacity-0 group-hover:opacity-100"></i></div><div class="absolute top-full left-1/2 -translate-x-1/2 mt-2 w-max bg-gray-900 text-white text-xs rounded py-1.5 px-3 opacity-0 group-hover:opacity-100 transition-opacity z-50 pointer-events-none shadow-lg">Total: <span class="font-bold">{{ grandTotals.serba35 }}</span></div></th><th @click="sortBy('serba50')" class="px-4 py-3 text-center cursor-pointer hover:bg-gray-100 select-none group relative"><div class="flex items-center justify-center gap-1">Serba 50 <i v-if="sortKey === 'serba50'" class="fa-solid text-blue-600" :class="sortAsc ? 'fa-sort-up' : 'fa-sort-down'"></i><i v-else class="fa-solid fa-sort text-gray-300 opacity-0 group-hover:opacity-100"></i></div><div class="absolute top-full left-1/2 -translate-x-1/2 mt-2 w-max bg-gray-900 text-white text-xs rounded py-1.5 px-3 opacity-0 group-hover:opacity-100 transition-opacity z-50 pointer-events-none shadow-lg">Total: <span class="font-bold text-yellow-300">{{ grandTotals.serba50 }}</span></div></th><th @click="sortBy('serba75')" class="px-4 py-3 text-center cursor-pointer hover:bg-gray-100 select-none group relative"><div class="flex items-center justify-center gap-1">Serba 75 <i v-if="sortKey === 'serba75'" class="fa-solid text-blue-600" :class="sortAsc ? 'fa-sort-up' : 'fa-sort-down'"></i><i v-else class="fa-solid fa-sort text-gray-300 opacity-0 group-hover:opacity-100"></i></div><div class="absolute top-full left-1/2 -translate-x-1/2 mt-2 w-max bg-gray-900 text-white text-xs rounded py-1.5 px-3 opacity-0 group-hover:opacity-100 transition-opacity z-50 pointer-events-none shadow-lg">Total: <span class="font-bold">{{ grandTotals.serba75 }}</span></div></th><th class="px-4 py-3 text-center w-28">Aksi</th></tr></thead><tbody><tr v-if="paginatedSales.length === 0"><td colspan="10" class="text-center py-8 text-gray-500">Data tidak ditemukan.</td></tr><tr v-for="item in paginatedSales" :key="item.id" :class="['bg-white border-b hover:bg-gray-50 transition-colors', selectedItems.has(item.id) ? 'bg-blue-50/60' : '']"><td class="px-4 py-4 text-center"><input type="checkbox" :checked="selectedItems.has(item.id)" @change="toggleSelect(item.id)" class="w-4 h-4 text-blue-600 rounded cursor-pointer accent-blue-600"></td><td class="px-4 py-4 font-medium text-gray-900">{{ item.salesNo }}</td><td class="px-4 py-4">{{ formatDateIndo(item.date) }}</td><td class="px-4 py-4"><span class="bg-blue-50 text-blue-700 py-1 px-2 rounded text-xs font-bold border border-blue-200">{{ item.namaCabang || '-' }}</span></td><td class="px-4 py-4 text-right font-mono">{{ formatRupiah(item.remainingMoney) }}</td><td class="px-4 py-4 text-right font-mono text-red-500">{{ formatRupiah(item.expense) }}</td><td class="px-4 py-4 text-right font-mono font-bold text-green-600">{{ formatRupiah(item.totalAll) }}</td><td class="px-4 py-4 text-center">{{ item.serba35 }}</td><td class="px-4 py-4 text-center font-medium text-yellow-600">{{ item.serba50 || 0 }}</td><td class="px-4 py-4 text-center">{{ item.serba75 }}</td><td class="px-4 py-4 text-center"><div class="flex items-center justify-center gap-1"><button @click="openEdit(item)" class="p-2 rounded-lg text-blue-500 hover:bg-blue-50 transition"><i class="fa-solid fa-pen text-sm"></i></button><button @click="handleSingleDelete(item)" class="p-2 rounded-lg text-red-500 hover:bg-red-50 transition"><i class="fa-solid fa-trash-can text-sm"></i></button></div></td></tr></tbody></table></div><div class="px-4 py-3 border-t bg-gray-50 flex flex-col sm:flex-row justify-between items-center gap-3"><div class="flex items-center gap-2 text-sm"><span class="text-gray-600">Tampilkan:</span><select v-model.number="itemsPerPage" class="border border-gray-300 rounded-lg px-2 py-1.5 text-sm focus:ring-blue-500 outline-none cursor-pointer"><option :value="5">5</option><option :value="10">10</option><option :value="25">25</option><option :value="50">50</option></select></div><div class="text-sm text-gray-600 order-first sm:order-none">Menampilkan <span class="font-semibold text-gray-800">{{ paginationInfo.start }}</span> - <span class="font-semibold text-gray-800">{{ paginationInfo.end }}</span> dari <span class="font-semibold text-gray-800">{{ filteredSales.length }}</span> data</div><div class="flex items-center gap-1"><button @click="currentPage = 1" :disabled="currentPage === 1" class=