ting ? 'Edit Penjualan' : 'Tambah Penjualan' }}</h3><button type="button" @click="closeModal" class="text-gray-400 hover:text-red-500 transition"><i class="fa-solid fa-xmark text-xl"></i></button></div><div v-if="!isEditing" class="flex border-b"><button type="button" @click="activeTab = 'single'" :class="['flex-1 py-3 text-sm font-medium transition-colors focus:outline-none', activeTab === 'single' ? 'border-b-2 border-blue-600 text-blue-600 bg-blue-50' : 'text-gray-500 hover:text-gray-700']">Input Satuan</button><button type="button" @click="activeTab = 'excel'" :class="['flex-1 py-3 text-sm font-medium transition-colors focus:outline-none', activeTab === 'excel' ? 'border-b-2 border-blue-600 text-blue-600 bg-blue-50' : 'text-gray-500 hover:text-gray-700']">Import Excel</button></div><div class="p-6 overflow-y-auto flex-1"><form v-if="activeTab === 'single' || isEditing" @submit.prevent="handleSubmit" class="space-y-4"><div class="grid grid-cols-1 md:grid-cols-2 gap-4"><div><label class="block text-sm font-medium text-gray-700 mb-1">Kode Penjualan</label><input v-model="form.salesNo" type="text" disabled class="w-full p-2.5 border border-gray-300 rounded-lg bg-gray-100 cursor-not-allowed" /></div><div><label class="block text-sm font-medium text-gray-700 mb-1">Tanggal <span class="text-red-500">*</span></label><input v-model="form.date" type="date" class="w-full p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" required /></div><div><label class="block text-sm font-medium text-gray-700 mb-1">Sisa Uang</label><div class="relative"><div class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none font-bold text-gray-500 text-xs">Rp</div><input v-model="form.remainingMoney" type="number" class="w-full p-2.5 pl-10 border border-gray-300 rounded-lg font-mono focus:ring-2 focus:ring-blue-500 outline-none" placeholder="0" /></div></div><div><label class="block text-sm font-medium text-gray-700 mb-1">Pengeluaran</label><div class="relative"><div class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none font-bold text-gray-500 text-xs">Rp</div><input v-model="form.expense" type="number" class="w-full p-2.5 pl-10 border border-gray-300 rounded-lg font-mono focus:ring-2 focus:ring-blue-500 outline-none" placeholder="0" /></div></div><div class="md:col-span-2"><label class="block text-sm font-medium text-gray-700 mb-1">Total Seluruh</label><div class="relative"><div class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none font-bold text-gray-500 text-xs">Rp</div><input v-model="form.totalAll" type="number" class="w-full p-2.5 pl-10 border border-gray-300 rounded-lg font-mono font-bold focus:ring-2 focus:ring-blue-500 outline-none" placeholder="0" /></div></div><div class="md:col-span-2 grid grid-cols-3 gap-3 pt-2 border-t"><div><label class="block text-sm font-medium text-gray-700 mb-1">Serba 35</label><input v-model="form.serba35" type="number" class="w-full p-2.5 border border-gray-300 rounded-lg text-center focus:ring-2 focus:ring-blue-500 outline-none" placeholder="0" /></div><div><label class="block text-sm font-medium text-gray-700 mb-1">Serba 50</label><input v-model="form.serba50" type="number" class="w-full p-2.5 border border-yellow-400 rounded-lg text-center focus:ring-2 focus:ring-yellow-500 outline-none bg-yellow-50" placeholder="0" /></div><div><label class="block text-sm font-medium text-gray-700 mb-1">Serba 75</label><input v-model="form.serba75" type="number" class="w-full p-2.5 border border-gray-300 rounded-lg text-center focus:ring-2 focus:ring-blue-500 outline-none" placeholder="0" /></div></div></div><div v-if="!isEditing" class="text-xs p-3 rounded mt-2 border bg-blue-50 text-blue-700 border-blue-200"><i class="fa-solid fa-info-circle mr-1"></i> Tanggal harus unik (hanya 1 data per tanggal per cabang).</div></form><div v-else class="space-y-4"><div @click="$refs.fileInput.click()" class="border-2 border-dashed rounded-xl p-8 text-center transition-colors cursor-pointer hover:border-blue-500 hover:bg-gray-50"><input type="file" ref="fileInput" class="hidden" accept=".xlsx, .xls" @change="handleFileSelect"><i :class="!excelFile ? 'fa-solid fa-file-excel text-4xl text-blue-500 mb-3' : 'fa-solid fa-file-circle-check text-4xl text-blue-600 mb-3'"></i><p class="text-gray-700 font-medium">{{ excelFile ? excelFile.name : 'Klik untuk Upload Excel (.xlsx)' }}</p><p class="text-xs text-gray-500 mt-1">Format: A(Kode), B(Tanggal), C(Sisa), D(Pengeluaran), E(Total), F(35), G(50), H(75)</p></div><div v-if="validationErrors.length > 0" class="bg-red-50 border border-red-200 rounded-lg p-4 max-h-40 overflow-y-auto"><h4 class="text-sm font-bold text-red-700 mb-2">⚠️ {{ validationErrors.length }} Data Error:</h4><ul class="list-disc list-inside text-xs text-red-600 space-y-1"><li v-for="(err, idx) in validationErrors.slice(0, 5)" :key="idx">{{ err }}</li></ul></div><div v-if="parsedExcelData.length > 0" class="text-xs border rounded-lg overflow-hidden"><div class="bg-blue-50 p-2 border-b font-bold text-blue-800">Siap Upload: {{ parsedExcelData.length }} Data Valid</div><div class="max-h-40 overflow-y-auto bg-white"><table class="w-full text-left"><tbody><tr v-for="(row, i) in parsedExcelData.slice(0, 5)" :key="i" class="border-b"><td class="p-2">{{ row.salesNo || 'Auto' }}</td><td class="p-2">{{ formatDateIndo(row.date) }}</td><td class="p-2">{{ formatRupiah(row.totalAll) }}</td></tr></tbody></table></div></div></div></div><div class="px-6 py-4 border-t bg-gray-50 flex gap-3 justify-end"><button type="button" @click="closeModal" class="px-5 py-2.5 text-gray-600 bg-white border border-gray-300 rounded-lg hover:bg-gray-100 font-medium transition">Batal</button><button v-if="activeTab === 'single' || isEditing" type="submit" @click="handleSubmit" class="px-6 py-2.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 font-medium transition shadow-sm">{{ isEditing ? 'Simpan Perubahan' : 'Tambah Data' }}</button><button v-else @click="handleExcelUpload" :disabled="!excelFile || parsedExcelData.length === 0" class="px-6 py-2.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 font-medium transition disabled:opacity-50 shadow-sm">Upload {{ parsedExcelData.length }} Data</button></div></div></div></Transition></Teleport><Teleport to="#modal-portal"><Transition name="modal"><div v-if="isAdminCabangModalOpen" class="fixed inset-0 z-[150] flex items-center justify-center p-4"><div class="absolute inset-0 bg-black/70 backdrop-blur-sm"></div><div class="relative bg-white w-full max-w-sm rounded-xl shadow-2xl border border-gray-100 z-20 pointer-events-auto"><div class="px-5 py-3 border-b flex justify-between items-center bg-purple-50"><h3 class="font-bold text-gray-800"><i class="fa-solid fa-warehouse text-purple-600 mr-2"></i>Pilih Cabang Tujuan</h3></div><form @submit.prevent="executeAdminUpload" class="p-5 space-y-4"><div><label class="block text-xs font-bold text-gray-700 mb-1">Masukkan ke Cabang</label><select v-model="selectedCabangForAdmin" class="w-full p-2.5 border rounded-lg focus:ring-2 focus:ring-purple-500 outline-none appearance-none bg-white font-bold" required><option disabled value="">Pilih Cabang...</option><option v-for="c in storeList" :key="c" :value="c">{{ c }}</option></select></div><div class="flex gap-2 pt-2"><button type="button" @click="isAdminCabangModalOpen = false" class="flex-1 py-2.5 text-gray-600 bg-gray-100 hover:bg-gray-200 rounded-lg font-medium transition">Batal</button><button type="submit" class="flex-1 py-2.5 bg-purple-600 text-white rounded-lg hover:bg-purple-700 font-medium transition">Lanjutkan</button></div></form></div></div></Transition></Teleport><Teleport to="#modal-portal"><Transition name="modal"><div v-if="isSingleDeleteModalOpen" class="fixed inset-0 z-[150] flex items-center justify-center p-4"><div @click="isSingleDeleteModalOpen = false" class="absolute inset-0 bg-black/60 backdrop-blur-sm"></div><div class="relative bg-white