.selectedItems]" :key="id" class="truncate font-medium">• {{ sales.find(i => i.id === id)?.salesNo }} ({{ formatDateIndo(sales.find(i => i.id === id)?.date) }})</p></div><p class="text-xs text-red-500 mb-4 font-semibold">*Data yang dihapus tidak dapat dikembalikan!</p><div class="flex gap-3 justify-center"><button @click="isBulkDeleteModalOpen = false" class="flex-1 py-2.5 text-gray-600 bg-gray-100 hover:bg-gray-200 rounded-lg font-medium transition">Batal</button><button @click="executeBulkDelete" class="flex-1 py-2.5 bg-red-600 text-white rounded-lg hover:bg-red-700 font-medium transition">Ya, Hapus Semua</button></div></div></div></Transition></Teleport><Teleport to="#modal-portal"><Transition name="modal"><div v-if="isUploading" class="fixed inset-0 z-[200] flex items-center justify-center p-4"><div class="absolute inset-0 bg-black/80 backdrop-blur-sm z-0"></div><div class="relative bg-white w-full max-w-md rounded-2xl shadow-2xl border border-gray-100 p-8 text-center z-10 pointer-events-none"><div class="mb-4"><div class="w-16 h-16 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin mx-auto"></div></div><h3 class="text-xl font-bold text-gray-800 mb-2">Sedang Mengupload...</h3><div class="w-full bg-gray-200 rounded-full h-4 mb-2 overflow-hidden relative"><div class="bg-gradient-to-r from-blue-500 to-indigo-600 h-4 rounded-full transition-all duration-300 ease-out" :style="{ width: uploadProgress + '%' }"></div></div><div class="flex justify-between items-center text-sm font-bold text-gray-700"><span>Proses: {{ uploadCount }} dari {{ uploadTotal }}</span><span>{{ Math.round(uploadProgress) }}%</span></div></div></div></Transition></Teleport></div></template>
<script setup>
import { ref, reactive, onMounted, computed, watch } from 'vue'; import SalesPresenter from './SalesPresenter'; import { STORE_LIST } from '../auth/AuthModel'; import { showToast } from '../../utils/toastify'; import ExcelJS from 'exceljs'; import Storage from '../../utils/storage';
const storeList = ref(STORE_LIST); const userData = ref(Storage.getUser()); const sales = ref([]); const isLoading = ref(false); const currentPage = ref(1); const itemsPerPage = ref(10); const sortKey = ref('date'); const sortAsc = ref(false); const filterCabang = ref(''); const searchQuery = ref(''); const startDate = ref(''); const endDate = ref('');
const isUploading = ref(false); const uploadTotal = ref(0); const uploadCount = ref(0); const uploadProgress = ref(0);
const isModalOpen = ref(false); const isEditing = ref(false); const activeTab = ref('single'); const form = reactive({ id: null, salesNo: '', date: '', remainingMoney: 0, expense: 0, totalAll: 0, serba35: 0, serba50: 0, serba75: 0 }); const excelFile = ref(null); const parsedExcelData = ref([]); const validationErrors = ref([]);
const selectedItems = ref(new Set()); const isSingleDeleteModalOpen = ref(false); const itemToDelete = ref(null); const isBulkDeleteModalOpen = ref(false);
const isAdminCabangModalOpen = ref(false); const selectedCabangForAdmin = ref(''); const pendingUploadData = ref(null);
const presenter = new SalesPresenter({ setSales: (data) => sales.value = data, showLoading: (state) => isLoading.value = state, onCreateSuccess: (msg) => { showToast(msg, 'success'); closeModal(); }, onUpdateSuccess: (msg) => { showToast(msg, 'success'); closeModal(); }, onDeleteSuccess: (msg) => { showToast(msg, 'success'); selectedItems.value.clear(); }, showError: (msg) => showToast(msg, 'error'), closeForm: () => {}, showUploadProgress: (state) => isUploading.value = state, setUploadTotal: (total) => uploadTotal.value = total, setUploadCount: (count) => uploadCount.value = count, updateProgress: (percent) => uploadProgress.value = percent });
const formatRupiah = (num) => !num && num !== 0 ? 'Rp 0' : new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR', maximumFractionDigits: 0 }).format(num);
const formatDateIndo = (dateString) => { if (!dateString) return '-'; const date = new Date(dateString); return isNaN(date.getTime()) ? dateString : date.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }); };
const sortBy = (key) => { if (sortKey.value === key) sortAsc.value = !sortAsc.value; else { sortKey.value = key; sortAsc.value = true; } currentPage.value = 1; };
const resetDateFilter = () => { startDate.value = ''; endDate.value = ''; };
const filteredSales = computed(() => { let t = [...sales.value]; if (userData.value?.role === 'admin' && filterCabang.value) { t = t.filter(i => i.namaCabang === filterCabang.value); } if (startDate.value && endDate.value) { const s = new Date(startDate.value); s.setHours(0,0,0,0); const e = new Date(endDate.value); e.setHours(23,59,59,999); t = t.filter(i => { const d = new Date(i.date); return d >= s && d <= e; }); } if(searchQuery.value) { const l = searchQuery.value.toLowerCase(); t = t.filter(i => (i.salesNo&&i.salesNo.toLowerCase().includes(l)) || (i.namaCabang&&i.namaCabang.toLowerCase().includes(l))); } t.sort((a, b) => { let valA = a[sortKey.value], valB = b[sortKey.value]; if (sortKey.value === 'date') { valA = new Date(valA).getTime(); valB = new Date(valB).getTime(); } else if (typeof valA === 'number' || typeof valB === 'number') { valA = Number(valA) || 0; valB = Number(valB) || 0; } else { valA = (valA||'').toLowerCase(); valB = (valB||'').toLowerCase(); } if (valA < valB) return sortAsc.value ? -1 : 1; if (valA > valB) return sortAsc.value ? 1 : -1; return 0; }); return t; });
const grandTotals = computed(() => filteredSales.value.reduce((acc, curr) => { acc.remainingMoney += Number(curr.remainingMoney) || 0; acc.expense += Number(curr.expense) || 0; acc.totalAll += Number(curr.totalAll) || 0; acc.serba35 += Number(curr.serba35) || 0; acc.serba50 += Number(curr.serba50) || 0; acc.serba75 += Number(curr.serba75) || 0; return acc; }, { remainingMoney: 0, expense: 0, totalAll: 0, serba35: 0, serba50: 0, serba75: 0 }));
const totalPages = computed(() => Math.ceil(filteredSales.value.length / itemsPerPage.value) || 1); const paginationInfo = computed(() => { const start = (currentPage.value - 1) * itemsPerPage.value + 1; return { start, end: Math.min(start + itemsPerPage.value - 1, filteredSales.value.length) }; }); const paginatedSales = computed(() => filteredSales.value.slice((currentPage.value - 1) * itemsPerPage.value, currentPage.value * itemsPerPage.value));
const isAllSelected = computed(() => paginatedSales.value.length > 0 && paginatedSales.value.every(i => selectedItems.value.has(i.id))); const toggleSelect = (id) => { if (selectedItems.value.has(id)) selectedItems.value.delete(id); else selectedItems.value.add(id); }; const toggleSelectAll = () => { if (isAllSelected.value) selectedItems.value.clear(); else paginatedSales.value.forEach(i => selectedItems.value.add(i.id)); };
const handleSingleDelete = (item) => { itemToDelete.value = item; isSingleDeleteModalOpen.value = true; }; const executeSingleDelete = async () => { if (!itemToDelete.value) return; await presenter.deleteSale(itemToDelete.value.id); isSingleDeleteModalOpen.value = false; itemToDelete.value = null; }; const executeBulkDelete = async () => { await presenter.bulkDelete([...selectedItems.value]); isBulkDeleteModalOpen.value = false; };
watch([itemsPerPage, filterCabang, startDate, endDate], () => { currentPage.value = 1; });
const injectCabangToData = (dataArray, cabang) => dataArray.map(d => ({ ...d, namaCabang: cabang }));
const handleSubmit = () => { if (!form.date) return showToast('Tanggal wajib diisi', 'error'); const payload = { ...form, remainingMoney: Number(form.remainingMoney), expense: Number(form.expense), totalAll: Number(form.totalAll), serba35: Number(form.serba35), serba50: Number(form.serba50), serba75: Number(form.serba75) }; if (isEditing.value) { presenter.updateSale(form.id, payload); return; } const user = Storage.getUser(); if (user?.role === 'admin') { pendingUploadData.value = [payload]; isAdminCabangModalOpen.value = true; } else { if (!user?.namaCabang) return showToast('Data cabang user tidak ditemukan', 'error'); presenter.createSale(injectCabangToData([payload], user.namaCabang)[0]); } };
const handleExcelUpload = () => { if (parsedExcelData.value.length === 0) return showToast('Tidak ada data valid', 'error'); const user = Storage.getUser(); if (user?.role === 'admin') { pendingUploadData.value = [...parsedExcelData.value]; isAdminCabangModalOpen.value = true; } else { if (!user?.namaCabang) return showToast('Data cabang user tidak ditemukan', 'error'); presenter.uploadExcel(injectCabangToData([...parsedExcelData.value], user.namaCabang)); closeModal(); } };
const executeAdminUpload = () => { if (!selectedCabangForAdmin.value) return showToast('Pilih cabang terlebih dahulu', 'error'); const finalData = injectCabangToData(pendingUploadData.value, selectedCabangForAdmin.value); isAdminCabangModalOpen.value = false; closeModal(); if (Array.isArray(finalData) && finalData.length > 1) presenter.uploadExcel(finalData); else presenter.createSale(finalData[0]); pendingUploadData.value = null; selectedCabangForAdmin.value = ''; };
const openModal = () => { isEditing.value = false; activeTab.value = 'single'; Object.assign(form, { id: null, salesNo: '', date: new Date().toISOString().split('T')[0], remainingMoney: 0, expense: 0, totalAll: 0, serba35: 0, serba50: 0, serba75: 0 }); excelFile.value = null; parsedExcelData.value = []; validationErrors.value = []; isModalOpen.value = true; }; const closeModal = () => isModalOpen.value = false;
const openEdit = (item) => { isEditing.value = true; activeTab.value = 'single'; let dv = item.date; if(typeof dv==='string'&&dv.includes('T')) dv=dv.split('T')[0]; Object.assign(form, { id: item.id, salesNo: item.salesNo, date: dv, remainingMoney: item.remainingMoney, expense: item.expense, totalAll: item.totalAll, serba35: item.serba35, serba50: item.serba50 || 0, serba75: item.serba75 }); isModalOpen.value = true; };
const handleFileSelect = async (e) => { if (!e.target.files.length) return; const file = e.target.files[0]; if (![".xlsx", ".xls"].includes(file.name.substring(file.name.lastIndexOf('.')))) return showToast('Format harus Excel', 'error'); excelFile.value = file; parsedExcelData.value = []; validationErrors.value = []; try { const workbook = new ExcelJS.Workbook(); await workbook.xlsx.load(await file.arrayBuffer()); const ws = workbook.getWorksheet(1); if (!ws) return showToast('Worksheet tidak ditemukan', 'error'); const validRows = [], errors = [], headers = []; ws.getRow(1).eachCell((c) => headers.push(c.value ? c.value.toString().toLowerCase().trim() : '')); const findCol = (names) => { for (const n of names) { const i = headers.findIndex(h => h && h.includes(n)); if (i !== -1) return i; } return -1; }; const cols = { no: findCol(["kode", "no penjualan"]), date: findCol(["tanggal", "date"]), sisa: findCol(["sisa uang", "sisa"]), exp: findCol(["pengeluaran", "expense"]), total: findCol(["total seluruh", "total"]), s35: findCol(["serba 35", "35"]), s50: findCol(["serba 50", "50"]), s75: findCol(["serba 75", "75"]) }; ws.eachRow((row, rn) => { if (rn === 1) return; const getVal = (idx) => idx !== -1 ? (row.getCell(idx + 1).value || "") : ""; let err = "", vd = "", dObj; const rawDate = getVal(cols.date); if (typeof rawDate === 'number') dObj = new Date((rawDate - 25569) * 86400 * 1000); else if (typeof rawDate === 'string') { const p = rawDate.split(/[-\/]/); dObj = p[0].length === 4 ? new Date(rawDate) : new Date(`${p[2]}-${p[1]}-${p[0]}`); } else if (rawDate instanceof Date) dObj = rawDate; if (!dObj || isNaN(dObj.getTime())) err = `Baris ${rn}: Tanggal tidak valid`; else { vd = dObj.toISOString().split('T')[0]; } const parseNum = (val) => typeof val === 'number' ? val : parseInt((val||'').replace(/\D/g, '')) || 0; if (err) errors.push(err); else validRows.push({ salesNo: getVal(cols.no), date: vd, remainingMoney: parseNum(getVal(cols.sisa)), expense: parseNum(getVal(cols.exp)), totalAll: parseNum(getVal(cols.total)), serba35: parseNum(getVal(cols.s35)), serba50: parseNum(getVal(cols.s50)), serba75: parseNum(getVal(cols.s75)) }); }); parsedExcelData.value = validRows; validationErrors.value = errors; } catch (err) { showToast('Gagal membaca Excel', 'error'); } };
const exportToExcel = async () => { if (filteredSales.value.length === 0) return showToast('Data kosong (Cek filter tanggal)', 'error'); const workbook = new ExcelJS.Workbook(); const sheet = workbook.addWorksheet('Data Penjualan'); const hs = { fill: { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF4F81BD' } }, font: { bold: true, color: { argb: 'FFFFFFFF' } }, alignment: { vertical: 'middle', horizontal: 'center' } }; sheet.columns = [ { header: 'Kode', key: 'salesNo', width: 20 }, { header: 'Tanggal', key: 'date', width: 15 }, { header: 'Cabang', key: 'cabang', width: 25 }, { header: 'Sisa Uang', key: 'remainingMoney', width: 20 }, { header: 'Pengeluaran', key: 'expense', width: 20 }, { header: 'Total Seluruh', key: 'totalAll', width: 20 }, { header: 'Serba 35', key: 'serba35', width: 12 }, { header: 'Serba 50', key: 'serba50', width: 12 }, { header: 'Serba 75', key: 'serba75', width: 12 } ]; sheet.getRow(1).eachCell((c) => c.style = hs); filteredSales.value.forEach(s => sheet.addRow({ ...s, serba50: s.serba50 || 0, cabang: s.namaCabang || '-', date: s.date ? new Date(s.date).toISOString().split('T')[0] : '-' })); const buffer = await workbook.xlsx.writeBuffer(); const blob = new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' }); const link = document.createElement('a'); link.href = window.URL.createObjectURL(blob); link.download = `Penjualan_${startDate.value || 'all'}_sd_${endDate.value || 'all'}.xlsx`; link.click(); showToast('Excel berhasil didownload', 'success'); };
onMounted(() => presenter.loadSales());
</script>
<style scoped>.modal-enter-active, .modal-leave-active { transition: opacity 0.3s ease; } .modal-enter-from, .modal-leave-to { opacity: 0; } .fab-enter-active, .fab-leave-active { transition: all 0.3s ease; } .fab-enter-from, .fab-leave-to { opacity: 0; transform: translateY(20px); }</style>